import { useMemo, useState } from "react";
import { Container, Nav, Navbar, Dropdown, Form, Button } from "react-bootstrap";
import { Link, useLocation, useNavigate } from "react-router-dom";

function AppNavbar({ user, setUser }) {
  const navigate = useNavigate();
  const location = useLocation();
  const [keyword, setKeyword] = useState("");

  const activeKey = useMemo(() => {
    if (location.pathname.startsWith("/profile")) return "profile";
    if (location.pathname.startsWith("/event")) return "events";
    return "home";
  }, [location.pathname]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    if (setUser) setUser(null);
    navigate("/login");
  };

  const handleSearch = (e) => {
    e.preventDefault();
    const params = new URLSearchParams();
    if (keyword.trim()) params.set("q", keyword.trim());
    navigate(`/home${params.toString() ? `?${params.toString()}` : ""}`);
  };

  const getInitial = () => {
    if (!user?.full_name) return "U";
    return user.full_name.trim().charAt(0).toUpperCase();
  };

  return (
    <Navbar expand="lg" className="app-navbar" variant="dark">
      <Container className="app-navbar-container">
        <Navbar.Brand as={Link} to={user ? "/home" : "/"} className="brand-wrap">
          <div className="brand-logo">CT</div>
          <div className="brand-text">
            <strong>Concert Ticket</strong>
            <small>Event booking platform</small>
          </div>
        </Navbar.Brand>

        <Navbar.Toggle aria-controls="main-navbar" />

        <Navbar.Collapse id="main-navbar">
          <Form className="navbar-search-form" onSubmit={handleSearch}>
            <Form.Control
              type="text"
              placeholder="Tìm sự kiện, nghệ sĩ, địa điểm..."
              value={keyword}
              onChange={(e) => setKeyword(e.target.value)}
            />
            <Button type="submit" className="btn-brand">
              Tìm
            </Button>
          </Form>

          <Nav className="mx-lg-4 ms-lg-4 navbar-links">
            <Nav.Link as={Link} to={user ? "/home" : "/"} className={activeKey === "home" ? "active" : ""}>
              Trang chủ
            </Nav.Link>
            <Nav.Link as={Link} to="/home" className={activeKey === "events" ? "active" : ""}>
              Sự kiện
            </Nav.Link>
            {user && (
              <Nav.Link as={Link} to="/profile" className={activeKey === "profile" ? "active" : ""}>
                Vé của tôi
              </Nav.Link>
            )}
          </Nav>
        </Navbar.Collapse>

        <div className="d-flex align-items-center ms-lg-2">
          {user ? (
            <Dropdown align="end">
              <Dropdown.Toggle variant="link" className="user-menu-toggle text-decoration-none border-0 shadow-none">
                <span className="user-avatar me-2">{getInitial()}</span>
                <span className="user-name d-none d-lg-inline">{user.full_name || "Người dùng"}</span>
              </Dropdown.Toggle>

              <Dropdown.Menu className="dropdown-modern border-0 shadow rounded-4 p-2">
                <Dropdown.Header className="fw-bold">
                  {user.full_name || "Người dùng"}
                </Dropdown.Header>
                <Dropdown.Item as={Link} to="/profile" className="rounded-3">
                  Hồ sơ & vé của tôi
                </Dropdown.Item>
                <Dropdown.Item as={Link} to="/home" className="rounded-3">
                  Khám phá sự kiện
                </Dropdown.Item>
                {user.role === "admin" && (
                  <Dropdown.Item as={Link} to="/admin" className="rounded-3">
                    Trang quản trị
                  </Dropdown.Item>
                )}
                <Dropdown.Divider />
                <Dropdown.Item onClick={handleLogout} className="rounded-3 text-danger fw-semibold">
                  Đăng xuất
                </Dropdown.Item>
              </Dropdown.Menu>
            </Dropdown>
          ) : (
            <div className="d-flex gap-2">
              <Link to="/login" className="btn btn-outline-light rounded-pill px-4">
                Đăng nhập
              </Link>
              <Link to="/register" className="btn btn-brand">
                Đăng ký
              </Link>
            </div>
          )}
        </div>
      </Container>
    </Navbar>
  );
}

export default AppNavbar;
